477→        mutation.mutate(variables, {
478→            ...options,
479→            onSettled: (data, error, vars, context) => {
480→                if (journalKey) inFlightRef.current.delete(journalKey);
481→                options?.onSettled?.(data, error, vars, context);
482→            },
483→        });
484→    };
485→
486→    return { ...mutation, mutate: guardedMutate };
487→}
